DO $$$ DECLARE admin_id uuid; aaron_id uuid; i int; rand_xp int; BEGIN SELECT id INTO admin_id FROM usuarios WHERE correo = 'admin@athletiq.app'; SELECT id INTO aaron_id FROM usuarios WHERE correo = 'aaron@athletiq.app'; IF admin_id IS NOT NULL THEN FOR i IN 0..6 LOOP rand_xp := floor(random() * 50 + 20)::int; INSERT INTO transacciones_xp (id, id_usuario, cantidad_xp, fecha_ganancia) VALUES (gen_random_uuid(), admin_id, rand_xp, NOW() - (i || ' days')::interval); END LOOP; UPDATE usuarios SET racha_actual = 7, racha_maxima = GREATEST(racha_maxima, 7), ultima_actividad = NOW() WHERE id = admin_id; END IF; IF aaron_id IS NOT NULL THEN FOR i IN 0..6 LOOP rand_xp := floor(random() * 60 + 30)::int; INSERT INTO transacciones_xp (id, id_usuario, cantidad_xp, fecha_ganancia) VALUES (gen_random_uuid(), aaron_id, rand_xp, NOW() - (i || ' days')::interval); END LOOP; UPDATE usuarios SET racha_actual = 7, racha_maxima = GREATEST(racha_maxima, 7), ultima_actividad = NOW() WHERE id = aaron_id; END IF; END $$$;
